module up_down_counter(
    input  clk,
    input  reset,
    input  dir,
    output [3:0] count
);

reg [3:0] cnt_reg;

always @(posedge clk) begin
    if (reset) begin
        cnt_reg <= 4'b0000;
    end else if (dir) begin
        cnt_reg <= cnt_reg + 1;
    end else begin
        cnt_reg <= cnt_reg - 1;
    end
end

assign count = cnt_reg;

endmodule
